# Amortized analysis: dynamic array (Python list)
class DynamicArray:
    def __init__(self):
        self._arr = [None] * 1
        self._size = 0
        self._capacity = 1

    def append(self, value):
        if self._size == self._capacity:
            self._resize(2 * self._capacity)
        self._arr[self._size] = value
        self._size += 1

    def _resize(self, new_cap):
        new_arr = [None] * new_cap
        for i in range(self._size):
            new_arr[i] = self._arr[i]
        self._arr = new_arr
        self._capacity = new_cap
        # Cost of resize is O(n), but happens every n appends -> O(1) amortized

# Cache-aware vs cache-oblivious
import time
import random

def sum_row_major(matrix):
    """Cache-friendly: sequential access (fast)"""
    total = 0
    for i in range(len(matrix)):
        for j in range(len(matrix[0])):
            total += matrix[i][j]
    return total

def sum_col_major(matrix):
    """Cache-unfriendly: strided access (slow)"""
    total = 0
    for j in range(len(matrix[0])):
        for i in range(len(matrix)):
            total += matrix[i][j]
    return total

