# Counting sort: O(n + k) where k is range
# Useful when k = O(n) — beats O(n log n) comparison sort
def counting_sort(arr, k):
    counts = [0] * (k + 1)
    for x in arr:
        counts[x] += 1
    i = 0
    for val in range(k + 1):
        for _ in range(counts[val]):
            arr[i] = val
            i += 1
    return arr

# Two-pointer optimal solution for container with most water
def max_area(heights):
    l, r = 0, len(heights) - 1
    best = 0
    while l < r:
        h = min(heights[l], heights[r])
        best = max(best, h * (r - l))
        if heights[l] < heights[r]:
            l += 1
        else:
            r -= 1
    return best
    # O(n) time, O(1) space
    # Proof: at each step we eliminate the shorter line
    # because any container using that line is bounded by it

# Sliding window: longest substring without repeating chars
def longest_unique_substring(s):
    last_seen = {}
    start = best = 0
    for i, ch in enumerate(s):
        if ch in last_seen and last_seen[ch] >= start:
            start = last_seen[ch] + 1
        last_seen[ch] = i
        best = max(best, i - start + 1)
    return best
    # O(n) time, O(min(n, alphabet_size)) space

# KMP pattern matching
def kmp_search(text, pattern):
    # Build LPS (Longest Prefix Suffix) array
    lps = [0] * len(pattern)
    j = 0
    for i in range(1, len(pattern)):
        while j > 0 and pattern[i] != pattern[j]:
            j = lps[j - 1]
        if pattern[i] == pattern[j]:
            j += 1
            lps[i] = j

    # Search
    i = j = 0
    while i < len(text):
        if text[i] == pattern[j]:
            i += 1; j += 1
        if j == len(pattern):
            return i - j  # match at this index
            j = lps[j - 1]
        elif i < len(text) and text[i] != pattern[j]:
            if j != 0:
                j = lps[j - 1]
            else:
                i += 1
    return -1
    # O(n + m) time, O(m) space

# Rolling hash (Rabin-Karp)
def rolling_hash(text, pattern):
    d = 256
    q = 101  # prime modulus
    M, N = len(pattern), len(text)
    p_hash = t_hash = 0
    h = pow(d, M - 1) % q

    for i in range(M):
        p_hash = (d * p_hash + ord(pattern[i])) % q
        t_hash = (d * t_hash + ord(text[i])) % q

    for i in range(N - M + 1):
        if p_hash == t_hash:
            if text[i:i+M] == pattern:
                return i
        if i < N - M:
            t_hash = (d * (t_hash - ord(text[i]) * h) + ord(text[i+M])) % q
    return -1

# Lock-free linked list (simplified CAS pattern)
import threading
import ctypes

class Node:
    def __init__(self, value):
        self.value = value
        self.next = None

class LockFreeQueue:
    def __init__(self):
        dummy = Node(None)
        self.head = dummy
        self.tail = dummy

    def enqueue(self, value):
        node = Node(value)
        while True:
            last = self.tail
            nxt = last.next
            if last is self.tail:  # consistent snapshot
                if nxt is None:
                    # try to link new node at end
                    if self._cas(last, 'next', nxt, node):
                        # try to swing tail
                        self._cas(self, 'tail', last, node)
                        return
                else:
                    # tail is falling behind — help move it
                    self._cas(self, 'tail', last, nxt)

    def dequeue(self):
        while True:
            first = self.head
            last = self.tail
            nxt = first.next
            if first is self.head:
                if first is last:
                    if nxt is None:
                        return None  # empty
                    self._cas(self, 'tail', last, nxt)
                else:
                    value = nxt.value
                    if self._cas(self, 'head', first, nxt):
                        return value

    def _cas(self, obj, attr, old, new):
        """Compare-and-swap on any object attribute."""
        # In real code, use atomic CAS (e.g., ctypes, C extension, or stdlib)
        with threading.Lock():
            if getattr(obj, attr) is old:
                setattr(obj, attr, new)
                return True
            return False

# Skip list (core operations)
import random

class SkipListNode:
    def __init__(self, key, value, level):
        self.key = key
        self.value = value
        self.forward = [None] * (level + 1)

class SkipList:
    MAX_LEVEL = 16
    P = 0.5

    def __init__(self):
        self.header = SkipListNode(None, None, self.MAX_LEVEL)
        self.level = 0

    def _random_level(self):
        level = 0
        while random.random() < self.P and level < self.MAX_LEVEL:
            level += 1
        return level

    def search(self, key):
        cur = self.header
        for i in range(self.level, -1, -1):
            while cur.forward[i] and cur.forward[i].key < key:
                cur = cur.forward[i]
        cur = cur.forward[0]
        if cur and cur.key == key:
            return cur.value
        return None

    def insert(self, key, value):
        update = [None] * (self.MAX_LEVEL + 1)
        cur = self.header
        for i in range(self.level, -1, -1):
            while cur.forward[i] and cur.forward[i].key < key:
                cur = cur.forward[i]
            update[i] = cur
        cur = cur.forward[0]
        if cur and cur.key == key:
            cur.value = value
        else:
            lvl = self._random_level()
            if lvl > self.level:
                for i in range(self.level + 1, lvl + 1):
                    update[i] = self.header
                self.level = lvl
            new_node = SkipListNode(key, value, lvl)
            for i in range(lvl + 1):
                new_node.forward[i] = update[i].forward[i]
                update[i].forward[i] = new_node

# Morris traversal (O(1) space tree traversal)
def morris_inorder(root):
    result = []
    cur = root
    while cur:
        if not cur.left:
            result.append(cur.val)
            cur = cur.right
        else:
            pre = cur.left
            while pre.right and pre.right is not cur:
                pre = pre.right
            if not pre.right:
                pre.right = cur
                cur = cur.left
            else:
                pre.right = None
                result.append(cur.val)
                cur = cur.right
    return result

# Dijkstra with heap
import heapq

def dijkstra(graph, start):
    """graph: adjacency list {node: [(neighbor, weight)]}"""
    dist = {node: float('inf') for node in graph}
    dist[start] = 0
    pq = [(0, start)]
    while pq:
        d, node = heapq.heappop(pq)
        if d > dist[node]:
            continue
        for neighbor, weight in graph[node]:
            nd = d + weight
            if nd < dist[neighbor]:
                dist[neighbor] = nd
                heapq.heappush(pq, (nd, neighbor))
    return dist

# Union-Find with path compression + union by rank
class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])  # path compression
        return self.parent[x]

    def union(self, x, y):
        px, py = self.find(x), self.find(y)
        if px == py:
            return False
        if self.rank[px] < self.rank[py]:
            self.parent[px] = py
        elif self.rank[px] > self.rank[py]:
            self.parent[py] = px
        else:
            self.parent[py] = px
            self.rank[px] += 1
        return True
    # Time: O(alpha(n)) per operation, practically O(1)

# Topological sort (Kahn's algorithm)
from collections import deque

def topological_sort(graph):
    in_degree = {node: 0 for node in graph}
    for node in graph:
        for neighbor in graph[node]:
            in_degree[neighbor] = in_degree.get(neighbor, 0) + 1

    queue = deque([n for n, d in in_degree.items() if d == 0])
    result = []
    while queue:
        node = queue.popleft()
        result.append(node)
        for neighbor in graph.get(node, []):
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    if len(result) != len(graph):
        return []  # cycle detected
    return result

# Bidirectional BFS for shortest path in unweighted graph
def bidirectional_bfs(graph, start, goal):
    if start == goal:
        return 0
    front = {start}
    back = {goal}
    dist = 0
    visited_front = {start}
    visited_back = {goal}

    while front and back:
        dist += 1
        # Expand smaller frontier
        if len(front) > len(back):
            front, back = back, front
            visited_front, visited_back = visited_back, visited_front

        next_front = set()
        for node in front:
            for neighbor in graph.get(node, []):
                if neighbor in back:
                    return dist
                if neighbor not in visited_front:
                    visited_front.add(neighbor)
                    next_front.add(neighbor)
        front = next_front
    return -1
    # Time: O(b^(d/2)) vs O(b^d) for standard BFS

# Floyd-Warshall (all-pairs shortest path)
def floyd_warshall(n, edges):
    INF = float('inf')
    dist = [[INF] * n for _ in range(n)]
    for i in range(n):
        dist[i][i] = 0
    for u, v, w in edges:
        dist[u][v] = w
    for k in range(n):
        for i in range(n):
            for j in range(n):
                if dist[i][k] + dist[k][j] < dist[i][j]:
                    dist[i][j] = dist[i][k] + dist[k][j]
    return dist
    # O(V^3) time, O(V^2) space

# 0/1 Knapsack — classic DP with state compression
def knapsack(weights, values, capacity):
    n = len(weights)
    dp = [0] * (capacity + 1)
    for i in range(n):
        for w in range(capacity, weights[i] - 1, -1):
            dp[w] = max(dp[w], dp[w - weights[i]] + values[i])
    return dp[capacity]
    # O(n * W) time, O(W) space
    # State compression: dp[w] from previous row only

# Longest Common Subsequence with path reconstruction
def lcs(text1, text2):
    m, n = len(text1), len(text2)
    dp = [[0] * (n + 1) for _ in range(m + 1)]
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if text1[i-1] == text2[j-1]:
                dp[i][j] = dp[i-1][j-1] + 1
            else:
                dp[i][j] = max(dp[i-1][j], dp[i][j-1])
    # Backtrack
    seq = []
    i, j = m, n
    while i > 0 and j > 0:
        if text1[i-1] == text2[j-1]:
            seq.append(text1[i-1])
            i -= 1; j -= 1
        elif dp[i-1][j] > dp[i][j-1]:
            i -= 1
        else:
            j -= 1
    return ''.join(reversed(seq))
    # O(m*n) time, O(m*n) space

# LCS with state compression (space O(min(m,n)))
def lcs_space_opt(a, b):
    if len(a) < len(b):
        a, b = b, a
    prev = [0] * (len(b) + 1)
    for i in range(1, len(a) + 1):
        curr = [0] * (len(b) + 1)
        for j in range(1, len(b) + 1):
            if a[i-1] == b[j-1]:
                curr[j] = prev[j-1] + 1
            else:
                curr[j] = max(prev[j], curr[j-1])
        prev = curr
    return prev[-1]

# DP on tree: diameter of binary tree
def tree_diameter(root):
    diameter = 0
    def height(node):
        nonlocal diameter
        if not node:
            return 0
        lh = height(node.left)
        rh = height(node.right)
        diameter = max(diameter, lh + rh)
        return 1 + max(lh, rh)
    height(root)
    return diameter

# Bitmask DP: Travelling Salesman Problem (O(n^2 * 2^n))
def tsp(dist):
    n = len(dist)
    dp = [[float('inf')] * n for _ in range(1 << n)]
    dp[1][0] = 0  # start at city 0
    for mask in range(1, 1 << n):
        if not mask & 1:  # must include start
            continue
        for last in range(1, n):
            if not mask & (1 << last):
                continue
            prev = mask ^ (1 << last)
            best = float('inf')
            for k in range(n):
                if prev & (1 << k):
                    best = min(best, dp[prev][k] + dist[k][last])
            dp[mask][last] = best
    full = (1 << n) - 1
    return min(dp[full][i] + dist[i][0] for i in range(1, n))

# Fenwick Tree (Binary Indexed Tree)
class BIT:
    def __init__(self, n):
        self.n = n
        self.tree = [0] * (n + 1)

    def add(self, idx, val):
        i = idx + 1
        while i <= self.n:
            self.tree[i] += val
            i += i & -i

    def sum(self, idx):
        res = 0
        i = idx
        while i > 0:
            res += self.tree[i]
            i -= i & -i
        return res

    def range_sum(self, l, r):
        return self.sum(r) - self.sum(l)

# Fenwick for range update + range query (with 2 BITs)
class RangeBIT:
    def __init__(self, n):
        self.B1 = BIT(n)
        self.B2 = BIT(n)

    def range_add(self, l, r, val):
        self.B1.add(l, val)
        self.B1.add(r + 1, -val)
        self.B2.add(l, val * (l - 1))
        self.B2.add(r + 1, -val * r)

    def prefix_sum(self, idx):
        return self.B1.sum(idx) * idx - self.B2.sum(idx)

    def range_sum(self, l, r):
        return self.prefix_sum(r) - self.prefix_sum(l)

# Segment Tree with lazy propagation
class SegTree:
    def __init__(self, arr):
        self.n = len(arr)
        self.tree = [0] * (4 * self.n)
        self.lazy = [0] * (4 * self.n)
        self._build(arr, 0, 0, self.n - 1)

    def _build(self, arr, node, l, r):
        if l == r:
            self.tree[node] = arr[l]
            return
        m = (l + r) // 2
        self._build(arr, node * 2 + 1, l, m)
        self._build(arr, node * 2 + 2, m + 1, r)
        self.tree[node] = self.tree[node * 2 + 1] + self.tree[node * 2 + 2]

    def _push(self, node, l, r):
        if self.lazy[node]:
            self.tree[node] += self.lazy[node] * (r - l + 1)
            if l != r:
                self.lazy[node * 2 + 1] += self.lazy[node]
                self.lazy[node * 2 + 2] += self.lazy[node]
            self.lazy[node] = 0

    def range_add(self, ql, qr, val, node=0, l=0, r=None):
        if r is None: r = self.n - 1
        self._push(node, l, r)
        if ql > r or qr < l:
            return
        if ql <= l and r <= qr:
            self.lazy[node] += val
            self._push(node, l, r)
            return
        m = (l + r) // 2
        self.range_add(ql, qr, val, node * 2 + 1, l, m)
        self.range_add(ql, qr, val, node * 2 + 2, m + 1, r)
        self.tree[node] = self.tree[node * 2 + 1] + self.tree[node * 2 + 2]

    def range_sum(self, ql, qr, node=0, l=0, r=None):
        if r is None: r = self.n - 1
        self._push(node, l, r)
        if ql > r or qr < l:
            return 0
        if ql <= l and r <= qr:
            return self.tree[node]
        m = (l + r) // 2
        return self.range_sum(ql, qr, node * 2 + 1, l, m) + self.range_sum(ql, qr, node * 2 + 2, m + 1, r)

# Trie with prefix search
class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for ch in word:
            if ch not in node.children:
                node.children[ch] = TrieNode()
            node = node.children[ch]
        node.is_end = True

    def search(self, word):
        node = self.root
        for ch in word:
            if ch not in node.children:
                return False
            node = node.children[ch]
        return node.is_end

    def starts_with(self, prefix):
        node = self.root
        for ch in prefix:
            if ch not in node.children:
                return False
            node = node.children[ch]
        return True

    def autocomplete(self, prefix, limit=10):
        node = self.root
        for ch in prefix:
            if ch not in node.children:
                return []
            node = node.children[ch]

        results = []
        stack = [(node, prefix)]
        while stack and len(results) < limit:
            n, w = stack.pop()
            if n.is_end:
                results.append(w)
            for ch in sorted(n.children.keys(), reverse=True):
                stack.append((n.children[ch], w + ch))
        return results

# Bitwise trie for max XOR pair
class BitTrie:
    def __init__(self, bits=31):
        self.root = {}
        self.bits = bits

    def insert(self, num):
        node = self.root
        for i in range(self.bits, -1, -1):
            bit = (num >> i) & 1
            if bit not in node:
                node[bit] = {}
            node = node[bit]

    def max_xor(self, num):
        node = self.root
        xor_val = 0
        for i in range(self.bits, -1, -1):
            bit = (num >> i) & 1
            flip = 1 - bit
            if flip in node:
                xor_val |= (1 << i)
                node = node[flip]
            else:
                node = node[bit]
        return xor_val

# Aho-Corasick automaton (simplified)
class AhoCorasick:
    def __init__(self):
        self.goto = [{}]  # trie transitions
        self.fail = [0]  # failure links
        self.output = [[]]  # patterns ending at this state

    def add(self, pattern):
        state = 0
        for ch in pattern:
            if ch not in self.goto[state]:
                self.goto[state][ch] = len(self.goto)
                self.goto.append({})
                self.fail.append(0)
                self.output.append([])
            state = self.goto[state][ch]
        self.output[state].append(pattern)

    def build(self):
        from collections import deque
        q = deque()
        for ch, nxt in self.goto[0].items():
            q.append(nxt)
            self.fail[nxt] = 0
        while q:
            r = q.popleft()
            for ch, u in self.goto[r].items():
                q.append(u)
                v = self.fail[r]
                while v and ch not in self.goto[v]:
                    v = self.fail[v]
                self.fail[u] = self.goto[v].get(ch, 0)
                self.output[u].extend(self.output[self.fail[u]])

    def search(self, text):
        state = 0
        results = []
        for i, ch in enumerate(text):
            while state and ch not in self.goto[state]:
                state = self.fail[state]
            state = self.goto[state].get(ch, 0)
            for pattern in self.output[state]:
                results.append((i - len(pattern) + 1, pattern))
        return results

# Consistent Hash Ring
import hashlib
import bisect

class ConsistentHash:
    def __init__(self, nodes=None, replicas=3):
        self.replicas = replicas
        self.ring = {}  # hash -> node
        self.sorted_keys = []
        if nodes:
            for node in nodes:
                self.add_node(node)

    def _hash(self, key):
        return int(hashlib.md5(key.encode()).hexdigest(), 16)

    def add_node(self, node):
        for i in range(self.replicas):
            key = self._hash(f"{node}:{i}")
            self.ring[key] = node
            bisect.insort(self.sorted_keys, key)

    def remove_node(self, node):
        for i in range(self.replicas):
            key = self._hash(f"{node}:{i}")
            del self.ring[key]
            self.sorted_keys.remove(key)

    def get_node(self, item):
        if not self.ring:
            return None
        h = self._hash(item)
        idx = bisect.bisect(self.sorted_keys, h) % len(self.sorted_keys)
        return self.ring[self.sorted_keys[idx]]

# Bloom Filter
import math
import struct
import hashlib

class BloomFilter:
    def __init__(self, n, fp_rate=0.01):
        """n = expected elements, fp_rate = target false positive rate"""
        self.n = n
        self.fp = fp_rate
        self.m = int(-n * math.log(fp_rate) / (math.log(2) ** 2))  # bits
        self.k = int((self.m / n) * math.log(2))  # hash functions
        self.bits = [0] * ((self.m + 7) // 8)

    def _hashes(self, item):
        """Generate k hash values using double hashing"""
        h1 = int(hashlib.md5(item.encode()).hexdigest(), 16)
        h2 = int(hashlib.sha1(item.encode()).hexdigest(), 16)
        return [(h1 + i * h2) % self.m for i in range(self.k)]

    def add(self, item):
        for h in self._hashes(item):
            byte_idx = h // 8
            bit_idx = h % 8
            self.bits[byte_idx] |= (1 << bit_idx)

    def contains(self, item):
        for h in self._hashes(item):
            byte_idx = h // 8
            bit_idx = h % 8
            if not (self.bits[byte_idx] & (1 << bit_idx)):
                return False
        return True

    def false_positive_rate(self):
        return (1 - math.exp(-self.k * self.n / self.m)) ** self.k

# Count-Min Sketch
import hashlib

class CountMinSketch:
    def __init__(self, epsilon=0.01, delta=0.01):
        self.w = int(math.ceil(math.e / epsilon))
        self.d = int(math.ceil(math.log(1 / delta)))
        self.sketch = [[0] * self.w for _ in range(self.d)]

    def add(self, item, count=1):
        for i in range(self.d):
            h = int(hashlib.md5(f"{item}:{i}".encode()).hexdigest(), 16) % self.w
            self.sketch[i][h] += count

    def estimate(self, item):
        return min(self.sketch[i][
            int(hashlib.md5(f"{item}:{i}".encode()).hexdigest(), 16) % self.w
        ] for i in range(self.d))

# Huffman coding (greedy)
import heapq
from collections import Counter

class HuffmanNode:
    def __init__(self, char, freq):
        self.char = char
        self.freq = freq
        self.left = None
        self.right = None

    def __lt__(self, other):
        return self.freq < other.freq

def huffman(text):
    freq = Counter(text)
    heap = [HuffmanNode(c, f) for c, f in freq.items()]
    heapq.heapify(heap)

    while len(heap) > 1:
        left = heapq.heappop(heap)
        right = heapq.heappop(heap)
        merged = HuffmanNode(None, left.freq + right.freq)
        merged.left = left
        merged.right = right
        heapq.heappush(heap, merged)

    root = heap[0]
    codes = {}
    def traverse(node, code):
        if node.char is not None:
            codes[node.char] = code
            return
        if node.left:
            traverse(node.left, code + '0')
        if node.right:
            traverse(node.right, code + '1')
    traverse(root, '')

    encoded = ''.join(codes[ch] for ch in text)
    return encoded, codes

# Quickselect (find k-th smallest)
import random

def quickselect(arr, k):
    """k is 0-indexed"""
    if len(arr) == 1:
        return arr[0]

    pivot = random.choice(arr)
    left = [x for x in arr if x < pivot]
    mid = [x for x in arr if x == pivot]
    right = [x for x in arr if x > pivot]

    if k < len(left):
        return quickselect(left, k)
    elif k < len(left) + len(mid):
        return pivot
    else:
        return quickselect(right, k - len(left) - len(mid))
    # O(n) expected time, O(n^2) worst case
    # Mitigate: median-of-medians for deterministic O(n)

# Median-of-medians (deterministic O(n) selection)
def mom_select(arr, k):
    """Deterministic O(n) selection"""
    if len(arr) <= 5:
        return sorted(arr)[k]

    # Split into groups of 5, find medians
    medians = []
    for i in range(0, len(arr), 5):
        group = sorted(arr[i:i+5])
        medians.append(group[len(group)//2])

    # Recursively find median of medians
    mom = mom_select(medians, len(medians)//2)

    # Partition around median of medians
    left = [x for x in arr if x < mom]
    mid = [x for x in arr if x == mom]
    right = [x for x in arr if x > mom]

    if k < len(left):
        return mom_select(left, k)
    elif k < len(left) + len(mid):
        return mom
    else:
        return mom_select(right, k - len(left) - len(mid))

# Closest pair of points (D&C)
def closest_pair(points):
    """points: list of (x, y)"""
    def dist(p1, p2):
        return ((p1[0]-p2[0])**2 + (p1[1]-p2[1])**2)**0.5

    def solve(px, py):
        if len(px) <= 3:
            return min(dist(px[i], px[j]) for i in range(len(px)) for j in range(i+1, len(px)))

        mid = len(px) // 2
        mid_x = px[mid][0]
        left_px = px[:mid]
        right_px = px[mid:]
        left_py = [p for p in py if p[0] <= mid_x]
        right_py = [p for p in py if p[0] > mid_x]

        d = min(solve(left_px, left_py), solve(right_px, right_py))

        # Strip: points within d of mid_x
        strip = [p for p in py if abs(p[0] - mid_x) < d]
        for i in range(len(strip)):
            for j in range(i + 1, min(i + 7, len(strip))):
                d = min(d, dist(strip[i], strip[j]))
        return d

    px = sorted(points, key=lambda p: p[0])
    py = sorted(points, key=lambda p: p[1])
    return solve(px, py)
    # O(n log n) time, O(n) space

# Readers-Writer Lock
import threading

class RWLock:
    def __init__(self):
        self._readers = 0
        self._write_lock = threading.Lock()
        self._read_lock = threading.Lock()

    def acquire_read(self):
        with self._read_lock:
            self._readers += 1
            if self._readers == 1:
                self._write_lock.acquire()

    def release_read(self):
        with self._read_lock:
            self._readers -= 1
            if self._readers == 0:
                self._write_lock.release()

    def acquire_write(self):
        self._write_lock.acquire()

    def release_write(self):
        self._write_lock.release()

# Work-stealing deque (simplified Chase-Lev deque)
# Used in ForkJoinPool, Go scheduler, Tokio
import random

class WorkStealingDeque:
    def __init__(self):
        self._tasks = []
        self._lock = threading.Lock()

    def push(self, task):
        """Owner thread pushes at bottom"""
        with self._lock:
            self._tasks.append(task)

    def pop(self):
        """Owner thread takes from bottom"""
        with self._lock:
            if self._tasks:
                return self._tasks.pop()
        return None

    def steal(self):
        """Thief thread takes from top"""
        with self._lock:
            if self._tasks:
                return self._tasks.pop(0)
        return None
    # In real Chase-Lev, uses CAS + atomic operations to avoid lock

# Parallel prefix sum (Blelloch scan)
def parallel_prefix_sum(arr):
    """Work-efficient parallel prefix sum
    Step 1: Up-sweep (build tree)
    Step 2: Down-sweep (propagate sums)
    O(log n) parallel time, O(n) work
    """
    n = len(arr)
    # In-place transformation
    tree = arr[:]

    # Up-sweep
    stride = 1
    while stride < n:
        i = 2 * stride - 1
        while i < n:
            tree[i] += tree[i - stride]
            i += 2 * stride
        stride *= 2

    # Down-sweep
    stride //= 2
    while stride > 0:
        i = stride - 1
        while i < n - stride:
            tree[i + stride] += tree[i]
            i += 2 * stride
        stride //= 2

    return tree  # prefix sums

# Thread-safe counter with atomic-like semantics
class AtomicCounter:
    def __init__(self, initial=0):
        self._value = initial
        self._lock = threading.Lock()

    def increment(self):
        with self._lock:
            self._value += 1
            return self._value

    def decrement(self):
        with self._lock:
            self._value -= 1
            return self._value

    def compare_and_swap(self, expected, new):
        with self._lock:
            if self._value == expected:
                self._value = new
                return True
            return False

    @property
    def value(self):
        return self._value

# Reservoir sampling
import random

def reservoir_sample(stream, k):
    """Select k random items from stream (unknown length)"""
    reservoir = []
    for i, item in enumerate(stream):
        if i < k:
            reservoir.append(item)
        else:
            j = random.randint(0, i)
            if j < k:
                reservoir[j] = item
    return reservoir
    # Each element has probability k/n of being in reservoir

# Weighted reservoir sampling (A-Chao algorithm)
def weighted_reservoir(stream, k):
    """Each item has (item, weight)"""
    reservoir = []
    for item, weight in stream:
        key = random.random() ** (1.0 / weight)
        if len(reservoir) < k:
            reservoir.append((key, item))
        else:
            # Find min key in reservoir
            min_idx = min(range(len(reservoir)), key=lambda i: reservoir[i][0])
            if key > reservoir[min_idx][0]:
                reservoir[min_idx] = (key, item)
    return [item for _, item in reservoir]

# Freivalds' matrix multiplication check
import random

def freivalds_check(A, B, C, trials=10):
    """Check if A * B == C with high probability
    O(n^2 * trials) vs O(n^3) for deterministic check
    """
    n = len(A)
    for _ in range(trials):
        r = [random.randint(0, 1) for _ in range(n)]
        # Compute B * r
        Br = [sum(B[i][j] * r[j] for j in range(n)) for i in range(n)]
        # Compute A * (B * r)
        ABr = [sum(A[i][j] * Br[j] for j in range(n)) for i in range(n)]
        # Compute C * r
        Cr = [sum(C[i][j] * r[j] for j in range(n)) for i in range(n)]

        if ABr != Cr:
            return False  # definitely wrong
    return True  # correct with probability >= 1 - 2^(-trials)

# Misra-Gries heavy hitters (items appearing > n/k times)
def misra_gries(stream, k):
    """Find all items with frequency > n/k in one pass"""
    counts = {}  # at most k-1 entries
    for item in stream:
        if item in counts:
            counts[item] += 1
        elif len(counts) < k - 1:
            counts[item] = 1
        else:
            # Decrement all
            to_remove = []
            for key in list(counts.keys()):
                counts[key] -= 1
                if counts[key] == 0:
                    to_remove.append(key)
            for key in to_remove:
                del counts[key]
    return list(counts.keys())
    # The algorithm guarantees: no false negatives,
    # but may have false positives (items < n/k threshold)
    # Second pass needed to filter exact counts.

# T-Digest (conceptual sketch)
# Used by Prometheus, Elasticsearch, Redis for streaming percentiles
class TDigest:
    def __init__(self, compression=100):
        self.centroids = []  # (mean, count)
        self.compression = compression

    def add(self, value):
        # Find nearest centroid
        if not self.centroids:
            self.centroids.append((value, 1))
            return
        nearest = min(range(len(self.centroids)),
                       key=lambda i: abs(self.centroids[i][0] - value))
        mean, count = self.centroids[nearest]
        new_count = count + 1
        new_mean = mean + (value - mean) / new_count
        self.centroids[nearest] = (new_mean, new_count)
        if new_count > self.compression / len(self.centroids):
            self._compress()

    def _compress(self):
        # Merge nearby centroids (simplified)
        self.centroids.sort(key=lambda x: x[0])
        merged = []
        for c in self.centroids:
            if merged and abs(merged[-1][0] - c[0]) < 1e-6:
                m, n1 = merged[-1]
                _, n2 = c
                new_n = n1 + n2
                merged[-1] = (m, new_n)  # simplified merge
            else:
                merged.append(c)
        self.centroids = merged

    def percentile(self, p):
        if not self.centroids:
            return 0
        total = sum(c[1] for c in self.centroids)
        target = total * p / 100
        cumulative = 0
        for mean, count in sorted(self.centroids, key=lambda x: x[0]):
            cumulative += count
            if cumulative >= target:
                return mean
        return self.centroids[-1][0]

